#include "libcapt/Compression/ScoaStreambuf.hpp"
#include "libcapt/Compression/Decoder/DecoderStreambuf.hpp"
#include "MemoryStream.hpp"
#include <exception>
#include <gtest/gtest.h>
#include <gmock/gmock.h>
#include <cstdint>
#include <ostream>
#include <vector>

using namespace Capt;

TEST(ScoaStreambufTest, General) {
    const std::vector<uint8_t> raster10x5 = {
        0x00, 0x01, 0x02, 0x03, 0x04, 0x05, 0x06, 0x07, 0x08, 0x09,
        0x10, 0x11, 0x12, 0x13, 0x14, 0x15, 0x16, 0x17, 0x18, 0x19,
        0x20, 0x21, 0x22, 0x23, 0x24, 0x25, 0x26, 0x27, 0x28, 0x29,
        0x30, 0x31, 0x32, 0x33, 0x34, 0x35, 0x36, 0x37, 0x38, 0x39,
        0x40, 0x41, 0x42, 0x43, 0x44, 0x45, 0x46, 0x47, 0x48, 0x49,
    };
    MemoryStream src(raster10x5);
    Compression::ScoaStreambuf ss(*src.rdbuf(), 10, 5);

    MemoryStream compressed;
    compressed << &ss;

    MemoryStream dst;
    Compression::DecoderStreambuf dec(*compressed.rdbuf(), 10, nullptr);
    dst << &dec;

    EXPECT_THAT(dst.Buffer(), testing::ElementsAreArray(raster10x5));
}

TEST(ScoaStreambufTest, PartialRaster) {
    const std::vector<uint8_t> partial10x5 = {
        0x00, 0x01, 0x02, 0x03, 0x04, 0x05, 0x06, 0x07, 0x08, 0x09,
        0x10, 0x11, 0x12, 0x13, 0x14, 0x15, 0x16, 0x17, 0x18, 0x19,
        0x20, 0x21, 0x22, 0x23, 0x24, 0x25, 0x26, 0x27, 0x28, 0x29,
        0x30, 0x31, 0x32, 0x33, 0x34, 0x35, 0x36, 0x37, 0x38, 0x39,
        0x40, 0x41, 0x42, 0x43, 0x44, 0x45,
    };
    const std::vector<uint8_t> expected = {
        0x00, 0x01, 0x02, 0x03, 0x04, 0x05, 0x06, 0x07, 0x08, 0x09,
        0x10, 0x11, 0x12, 0x13, 0x14, 0x15, 0x16, 0x17, 0x18, 0x19,
        0x20, 0x21, 0x22, 0x23, 0x24, 0x25, 0x26, 0x27, 0x28, 0x29,
        0x30, 0x31, 0x32, 0x33, 0x34, 0x35, 0x36, 0x37, 0x38, 0x39,
    };

    MemoryStream src(partial10x5);
    Compression::ScoaStreambuf ss(*src.rdbuf(), 10, 5);

    MemoryStream compressed;
    compressed << &ss;

    MemoryStream dst;
    try {
        dst.exceptions(std::ios_base::badbit | std::ios_base::failbit | std::ios_base::eofbit);
        Compression::DecoderStreambuf dec(*compressed.rdbuf(), 10, nullptr);
        dst << &dec;
    } catch (const std::exception&) {}

    EXPECT_THAT(dst.Buffer(), testing::ElementsAreArray(expected));
}
